mapper.update:
update se_supervision_instance

    gmt_modified = CURRENT_TIMESTAMP
    ,supervision_reason = #{supervisionInstanceEntity.supervisionReason}
    ,supervision_type = #{supervisionInstanceEntity.supervisionType}
    ,status = #{supervisionInstanceEntity.status}
    ,close_time = #{supervisionInstanceEntity.closeTime}

where id = #{supervisionInstanceEntity.id}
 and tenant_id = #{supervisionInstanceEntity.tenantId}

mapper.select:
select

from se_supervision_instance 
where id = #{id}
 and tenant_id = #{tenantId}

select

from se_supervision_instance 
where task_instance_id = #{taskInstanceId}
  and status = 'active'
 and tenant_id = #{tenantId} 
order by gmt_create desc

select

from se_supervision_instance 
where supervisor_user_id = #{supervisorUserId}
 and tenant_id = #{tenantId} 
order by gmt_create desc
limit #{pageSize} offset #{pageOffset}

select count(*)
from se_supervision_instance 
where supervisor_user_id = #{supervisorUserId}
 and tenant_id = #{tenantId}

mapper.update:
update se_supervision_instance
set status = 'closed',
    close_time = CURRENT_TIMESTAMP,
    gmt_modified = CURRENT_TIMESTAMP
where id = #{id}
 and tenant_id = #{tenantId}

mapper.delete:
delete from se_supervision_instance
where id = #{id}
 and tenant_id = #{tenantId}
